#include<cstdio>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
const int N=2e5+10,BK=128,Mod=1e9+7;inline void DN(int &x){x>=Mod?x-=Mod:0;} inline void UP(int &x){x<0?x+=Mod:0;}
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res==Mod?0:res;
}
int buf[N<<1],*Tmp=buf,n,loc[N],ql[N/BK+20],qr[N/BK+20],blk,sm[N/BK+20],s[BK+10][BK+10],a[N],Sum;
inline int qry(const int &l,const int &r)
{
	int L=loc[l],R=loc[r],res=0;if(L==R){rep(l,r,i)DN(res+=a[i]);return res;}
	rep(l,qr[L],i)DN(res+=a[i]);rep(L+1,R-1,i)DN(res+=sm[i]);rep(ql[R],r,i)DN(res+=a[i]);return res;
}
inline int sum(const int &x,const int &l,const int &r){int q=s[x][r]-s[x][l-1];UP(q);return q;}
int main()
{
//	FIN("data.in");//FOUT("mine.out");
	n=read();int Q=read();rep(1,n,i)DN(sm[loc[i]=(i-1)/BK+1]+=(a[i]=read()));
	blk=loc[n];rep(1,blk,i){ql[i]=qr[i-1]+1,qr[i]=i*BK;}qr[blk]=n;
	while(Q--)
	{
		if(read()==1)
		{
			int x=read(),y=read(),z=read();if(x==1)DN(Sum+=z);
			else if(x<=BK)rep(y,x,i)DN(s[x][i]+=z);
			else for(int i=y;i<=n;i+=x)DN(a[i]+=z),DN(sm[loc[i]]+=z);
		}
		else
		{
			int l=read(),r=read(),res=qry(l,r);
			rep(2,BK,x)
			{
				
				int bl=(l-1)/x+1,br=(r-1)/x+1;
//				if(x<=10)printf("%d :: %d %d %d %d\n",x,bl,br,(l-1)%x+1,(r-1)%x+1);
				if(bl==br){DN(res+=sum(x,(l-1)%x+1,(r-1)%x+1));}
				else
				{
					res=(1ll*(br-bl-1)*s[x][x]+res)%Mod;
//					printf("case 1 :: %d\n",res);
					DN(res+=sum(x,(l-1)%x+1,x));
//					printf("case 2 :: %d\n",res);
					DN(res+=sum(x,1,(r-1)%x+1));
				}
			}
			res=(1ll*(r-l+1)*Sum+res)%Mod;printf("%d\n",res);
		}
//		printf("debug::\n");
//		rep(1,10,x){rep(1,x,y)printf("%d ",s[x][y]);putchar('\n');}
	}
}
